SELECT SUM(debit - credit) AS total_amount
FROM transactions
WHERE status = 'FAILED';

SELECT SUM(debit) AS total_debit
FROM transactions
WHERE user_id = 1 AND status = 'SUCCESS' AND payment_method = 'Credit Card';

SELECT SUM(balance) AS total_customer_balance
FROM wallets
WHERE user_type = 'customer' AND balance > 500;
